      "a^m a^n=a^{m+n}",
      "\\log_a b=c \\Leftrightarrow a^c=b",
      "\\sin\\alpha=\\frac{priešpriešinė}{įžambinė}",
      "\\frac{d}{dx}x^n = nx^{n-1}",
      "\\int x^n dx = \\frac{x^{n+1}}{n+1}+C"
